SET default_table_access_method = heap;

--
-- Name: courses; Type: TABLE; Schema: public; Owner: neetadmin
--

CREATE TABLE public.courses (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    mongo_id character varying(255),
    title character varying(255) NOT NULL,
    sub_title character varying(255) DEFAULT ''::character varying,
    description text DEFAULT ''::text,
    category character varying(255) NOT NULL,
    level character varying(255) DEFAULT ''::character varying,
    price numeric(10,2) DEFAULT 0,
    thumbnail character varying(500) DEFAULT ''::character varying,
    creator_id uuid NOT NULL,
    is_published boolean DEFAULT false,
    created_at timestamp without time zone DEFAULT CURRENT_TIMESTAMP,
    updated_at timestamp without time zone DEFAULT CURRENT_TIMESTAMP
);


ALTER TABLE public.courses OWNER TO neetadmin;

