--
-- Name: notes; Type: TABLE; Schema: public; Owner: neetadmin
--

CREATE TABLE public.notes (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    mongo_id character varying(255),
    class character varying(2) NOT NULL,
    subject character varying(255) NOT NULL,
    chapter character varying(255) NOT NULL,
    title character varying(255) DEFAULT ''::character varying,
    note_text text NOT NULL,
    images text[] DEFAULT ARRAY[]::text[],
    educator_id uuid NOT NULL,
    type character varying(20) DEFAULT 'pyq'::character varying NOT NULL,
    created_at timestamp without time zone DEFAULT CURRENT_TIMESTAMP,
    updated_at timestamp without time zone DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT notes_class_check CHECK (((class)::text = ANY ((ARRAY['11'::character varying, '12'::character varying])::text[]))),
    CONSTRAINT notes_type_check CHECK (((type)::text = ANY ((ARRAY['pyq'::character varying, 'question-bank'::character varying])::text[])))
);


ALTER TABLE public.notes OWNER TO neetadmin;

