    password character varying(255),
    description text,
    role character varying(20) NOT NULL,
    photo_url character varying(500) DEFAULT ''::character varying,
    reset_otp character varying(255),
    otp_expires timestamp without time zone,
    is_otp_verifed boolean DEFAULT false,
    last_mcq_submission timestamp without time zone,
    created_at timestamp without time zone DEFAULT CURRENT_TIMESTAMP,
    updated_at timestamp without time zone DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT users_role_check CHECK (((role)::text = ANY ((ARRAY['educator'::character varying, 'student'::character varying, 'admin'::character varying])::text[])))
);


ALTER TABLE public.users OWNER TO neetadmin;

